## Client Implementation

```javascript
// React hook
import { useEffect, useState } from 'react';
import { io } from 'socket.io-client';

function useChatSocket(roomId, token) {
  const [socket, setSocket] = useState(null);
  const [messages, setMessages] = useState([]);
  const [connected, setConnected] = useState(false);

  useEffect(() => {
    // Connect with auth
    const newSocket = io('https://api.example.com', {
      auth: { token },
      reconnection: true,
      reconnectionDelay: 1000,
      reconnectionDelayMax: 5000,
      reconnectionAttempts: 5
    });

    // Connection events
    newSocket.on('connect', () => {
      console.log('Connected');
      setConnected(true);
      newSocket.emit('room:join', roomId);
    });

    newSocket.on('disconnect', (reason) => {
      console.log('Disconnected:', reason);
      setConnected(false);
    });

    newSocket.on('connect_error', (err) => {
      console.error('Connection error:', err);
    });

    // Message events
    newSocket.on('chat:message', (message) => {
      setMessages(prev => [...prev, message]);
    });

    setSocket(newSocket);

    return () => {
      newSocket.close();
    };
  }, [roomId, token]);

  const sendMessage = (content) => {
    if (socket?.connected) {
      socket.emit('chat:send', { content, roomId });
    }
  };

  return { messages, sendMessage, connected };
}

// Usage
function ChatRoom({ roomId, token }) {
  const { messages, sendMessage, connected } = useChatSocket(roomId, token);

  return (
    <div>
      <div>Status: {connected ? 'Connected' : 'Disconnected'}</div>
      <div>
        {messages.map(msg => (
          <div key={msg.id}>{msg.username}: {msg.content}</div>
        ))}
      </div>
      <input onKeyPress={e => {
        if (e.key === 'Enter') {
          sendMessage(e.target.value);
          e.target.value = '';
        }
      }} />
    </div>
  );
}
```

