  socket.on('disconnect', () => {
    connectionsGauge.dec();
  });

  socket.on('message', (data) => {
    const start = Date.now();
    messagesCounter.inc({ type: data.type });

    // ... handle message ...

    latencyHistogram.observe((Date.now() - start) / 1000);
  });
});
